/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Listagem de Cidades"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &UfeCod.IsEmpty() print printBlockFilterUfeCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CIDNOM' &CidNom1.FromString(&GridStateDynamicFilter.Value) If not &CidNom1.IsEmpty() &CidNom = &CidNom1 print printBlockFilterCidNom EndIf Case &DynamicFiltersSelector1 = !'CIDCOD' &CidCod1.FromString(&GridStateDynamicFilter.Value) If not &CidCod1.IsEmpty() &CidCod = &CidCod1 print printBlockFilterCidCod EndIf Case &DynamicFiltersSelector1 = !'CIDIBGE' &CidIBGE1.FromString(&GridStateDynamicFilter.Value) If not &CidIBGE1.IsEmpty() &CidIBGE = &CidIBGE1 print printBlockFilterCidIBGE EndIf Case &DynamicFiltersSelector1 = !'PAICOD' &PaiCod1.FromString(&GridStateDynamicFilter.Value) If not &PaiCod1.IsEmpty() &PaiCod = &PaiCod1 print printBlockFilterPaiCod EndIf Case &DynamicFiltersSelector1 = !'CIDARECOD' &CidAreCod1.FromString(&GridStateDynamicFilter.Value) If not &CidAreCod1.IsEmpty() &CidAreCod = &CidAreCod1 print printBlockFilterCidAreCod EndIf Case &DynamicFiltersSelector1 = !'CIDTRACOD' &CidTraCod1.FromString(&GridStateDynamicFilter.Value) If not &CidTraCod1.IsEmpty() &CidTraCod = &CidTraCod1 print printBlockFilterCidTraCod EndIf Case &DynamicFiltersSelector1 = !'CIDTRARAZ' &CidTraRaz1.FromString(&GridStateDynamicFilter.Value) If not &CidTraRaz1.IsEmpty() &CidTraRaz = &CidTraRaz1 print printBlockFilterCidTraRaz EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CIDNOM' &CidNom2.FromString(&GridStateDynamicFilter.Value) If not &CidNom2.IsEmpty() &CidNom = &CidNom2 print printBlockFilterCidNom EndIf Case &DynamicFiltersSelector2 = !'CIDCOD' &CidCod2.FromString(&GridStateDynamicFilter.Value) If not &CidCod2.IsEmpty() &CidCod = &CidCod2 print printBlockFilterCidCod EndIf Case &DynamicFiltersSelector2 = !'CIDIBGE' &CidIBGE2.FromString(&GridStateDynamicFilter.Value) If not &CidIBGE2.IsEmpty() &CidIBGE = &CidIBGE2 print printBlockFilterCidIBGE EndIf Case &DynamicFiltersSelector2 = !'PAICOD' &PaiCod2.FromString(&GridStateDynamicFilter.Value) If not &PaiCod2.IsEmpty() &PaiCod = &PaiCod2 print printBlockFilterPaiCod EndIf Case &DynamicFiltersSelector2 = !'CIDARECOD' &CidAreCod2.FromString(&GridStateDynamicFilter.Value) If not &CidAreCod2.IsEmpty() &CidAreCod = &CidAreCod2 print printBlockFilterCidAreCod EndIf Case &DynamicFiltersSelector2 = !'CIDTRACOD' &CidTraCod2.FromString(&GridStateDynamicFilter.Value) If not &CidTraCod2.IsEmpty() &CidTraCod = &CidTraCod2 print printBlockFilterCidTraCod EndIf Case &DynamicFiltersSelector2 = !'CIDTRARAZ' &CidTraRaz2.FromString(&GridStateDynamicFilter.Value) If not &CidTraRaz2.IsEmpty() &CidTraRaz = &CidTraRaz2 print printBlockFilterCidTraRaz EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CIDNOM' &CidNom3.FromString(&GridStateDynamicFilter.Value) If not &CidNom3.IsEmpty() &CidNom = &CidNom3 print printBlockFilterCidNom EndIf Case &DynamicFiltersSelector3 = !'CIDCOD' &CidCod3.FromString(&GridStateDynamicFilter.Value) If not &CidCod3.IsEmpty() &CidCod = &CidCod3 print printBlockFilterCidCod EndIf Case &DynamicFiltersSelector3 = !'CIDIBGE' &CidIBGE3.FromString(&GridStateDynamicFilter.Value) If not &CidIBGE3.IsEmpty() &CidIBGE = &CidIBGE3 print printBlockFilterCidIBGE EndIf Case &DynamicFiltersSelector3 = !'PAICOD' &PaiCod3.FromString(&GridStateDynamicFilter.Value) If not &PaiCod3.IsEmpty() &PaiCod = &PaiCod3 print printBlockFilterPaiCod EndIf Case &DynamicFiltersSelector3 = !'CIDARECOD' &CidAreCod3.FromString(&GridStateDynamicFilter.Value) If not &CidAreCod3.IsEmpty() &CidAreCod = &CidAreCod3 print printBlockFilterCidAreCod EndIf Case &DynamicFiltersSelector3 = !'CIDTRACOD' &CidTraCod3.FromString(&GridStateDynamicFilter.Value) If not &CidTraCod3.IsEmpty() &CidTraCod = &CidTraCod3 print printBlockFilterCidTraCod EndIf Case &DynamicFiltersSelector3 = !'CIDTRARAZ' &CidTraRaz3.FromString(&GridStateDynamicFilter.Value) If not &CidTraRaz3.IsEmpty() &CidTraRaz = &CidTraRaz3 print printBlockFilterCidTraRaz EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each Cidade order EmpCod CidNom when &OrderedBy = 1 order CidCod when &OrderedBy = 2 AND &OrderedDsc = False order (CidCod) when &OrderedBy = 2 AND &OrderedDsc = True order CidNom when &OrderedBy = 3 AND &OrderedDsc = False order (CidNom) when &OrderedBy = 3 AND &OrderedDsc = True order CidIBGE when &OrderedBy = 4 AND &OrderedDsc = False order (CidIBGE) when &OrderedBy = 4 AND &OrderedDsc = True order UfeCod when &OrderedBy = 5 AND &OrderedDsc = False order (UfeCod) when &OrderedBy = 5 AND &OrderedDsc = True order UfeNom when &OrderedBy = 6 AND &OrderedDsc = False order (UfeNom) when &OrderedBy = 6 AND &OrderedDsc = True order PaiCod when &OrderedBy = 7 AND &OrderedDsc = False order (PaiCod) when &OrderedBy = 7 AND &OrderedDsc = True order PaiNom when &OrderedBy = 8 AND &OrderedDsc = False order (PaiNom) when &OrderedBy = 8 AND &OrderedDsc = True order CidAreCodNom when &OrderedBy = 9 AND &OrderedDsc = False order (CidAreCodNom) when &OrderedBy = 9 AND &OrderedDsc = True
Where UfeCod Like &UfeCod when not &UfeCod.IsEmpty() Where CidNom like &CidNom1 when &DynamicFiltersSelector1 = !'CIDNOM' AND (not &CidNom1.IsEmpty()) Where CidCod = &CidCod1 when &DynamicFiltersSelector1 = !'CIDCOD' AND (not &CidCod1.IsEmpty()) Where CidIBGE = &CidIBGE1 when &DynamicFiltersSelector1 = !'CIDIBGE' AND (not &CidIBGE1.IsEmpty()) Where PaiCod = &PaiCod1 when &DynamicFiltersSelector1 = !'PAICOD' AND (not &PaiCod1.IsEmpty()) Where CidAreCod = &CidAreCod1 when &DynamicFiltersSelector1 = !'CIDARECOD' AND (not &CidAreCod1.IsEmpty()) Where CidTraCod = &CidTraCod1 when &DynamicFiltersSelector1 = !'CIDTRACOD' AND (not &CidTraCod1.IsEmpty()) Where CidTraRaz like &CidTraRaz1 when &DynamicFiltersSelector1 = !'CIDTRARAZ' AND (not &CidTraRaz1.IsEmpty()) Where CidNom like &CidNom2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDNOM' AND (not &CidNom2.IsEmpty()) Where CidCod = &CidCod2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDCOD' AND (not &CidCod2.IsEmpty()) Where CidIBGE = &CidIBGE2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDIBGE' AND (not &CidIBGE2.IsEmpty()) Where PaiCod = &PaiCod2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'PAICOD' AND (not &PaiCod2.IsEmpty()) Where CidAreCod = &CidAreCod2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDARECOD' AND (not &CidAreCod2.IsEmpty()) Where CidTraCod = &CidTraCod2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDTRACOD' AND (not &CidTraCod2.IsEmpty()) Where CidTraRaz like &CidTraRaz2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDTRARAZ' AND (not &CidTraRaz2.IsEmpty()) Where CidNom like &CidNom3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDNOM' AND (not &CidNom3.IsEmpty()) Where CidCod = &CidCod3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDCOD' AND (not &CidCod3.IsEmpty()) Where CidIBGE = &CidIBGE3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDIBGE' AND (not &CidIBGE3.IsEmpty()) Where PaiCod = &PaiCod3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'PAICOD' AND (not &PaiCod3.IsEmpty()) Where CidAreCod = &CidAreCod3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDARECOD' AND (not &CidAreCod3.IsEmpty()) Where CidTraCod = &CidTraCod3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDTRACOD' AND (not &CidTraCod3.IsEmpty()) Where CidTraRaz like &CidTraRaz3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDTRARAZ' AND (not &CidTraRaz3.IsEmpty()) Where EmpCod = ProcRetCompany.Udp()
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWCidadeGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWCidadeGridState")) Else &GridState.FromXml(&Session.Get(!"WWCidadeGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"UFECOD" &UfeCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
